//
// Unless required by applicable law or agreed to in writing, software
// distributed under the License is distributed on an "AS IS" BASIS,
// WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
// See the License for the specific language governing permissions and
// limitations under the License.

package sandbox

import "errors"

// ErrInvalidCommand is returned when a command is invalid (e.g., empty path).
var ErrInvalidCommand = errors.New("sandbox: invalid command")

// ErrProcessNotFound is returned when a process cannot be found.
var ErrProcessNotFound = errors.New("sandbox: process not found")

// ErrVMNotRunning is returned when the VM is not running.
var ErrVMNotRunning = errors.New("sandbox: vm not running")

// ErrAgentNotConnected is returned when the guest agent is not connected.
var ErrAgentNotConnected = errors.New("sandbox: agent not connected")

// ErrUnsupportedPlatform is returned when the platform is not supported.
var ErrUnsupportedPlatform = errors.New("sandbox: unsupported platform")

// ErrTimeout is returned when an operation times out.
var ErrTimeout = errors.New("sandbox: timeout")

// ErrClosed is returned when the executor has been closed.
var ErrClosed = errors.New("sandbox: executor closed")

