package sandboxrpc

import (
	"context"
	"fmt"
	"io"
	"log/slog"
	"syscall"
	"time"

	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
	"google.golang.org/grpc"
)

const defaultTimeout = 5 * time.Second

// Client connects to the guest agent running inside the sandbox VM.
type Client struct {
	agent AgentClient
	ctx   context.Context
	log   *slog.Logger
}

// NewClient creates a new client connected to the agent via the given gRPC
// connection.
func NewClient(ctx context.Context, cc grpc.ClientConnInterface) *Client {
	return &Client{
		agent: NewAgentClient(cc),
		ctx:   ctx,
		log:   slog.Default().With("struct", "sandboxrpc.Client"),
	}
}

// StartCommand starts a command in the sandbox and returns its PID.
// The cmd's Stdin, Stdout, and Stderr are streamed to/from the sandbox.
func (c *Client) StartCommand(
	ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
	stream, err := c.agent.StartCommand(ctx)
	if err != nil {
		return 0, fmt.Errorf("start command stream: %w", err)
	}

	streamer := newClientStreamer(ctx, cmd, stream, c.log)
	return streamer.start()
}

// Signal sends a signal to a process running in the sandbox.
func (c *Client) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
	ctx, cancel := context.WithTimeout(c.ctx, defaultTimeout)
	defer cancel()

	_, err := c.agent.Signal(ctx, &SignalRequest{
		Pid:    int64(pid),
		Signal: int32(sig),
	})
	return err
}

// Ping checks if the agent is alive.
func (c *Client) Ping(ctx context.Context) error {
	ctx, cancel := context.WithTimeout(ctx, defaultTimeout)
	defer cancel()

	_, err := c.agent.Ping(ctx, &PingRequest{})
	return err
}

// Close closes the client.
func (c *Client) Close() error {
	return nil
}

// clientStreamer handles bidirectional streaming for a command.
type clientStreamer struct {
	cmd    workspaceapi.Cmd
	stream Agent_StartCommandClient
	ctx    context.Context
	quitCh chan struct{}
	log    *slog.Logger
}

func newClientStreamer(
	ctx context.Context,
	cmd workspaceapi.Cmd,
	stream Agent_StartCommandClient,
	log *slog.Logger,
) *clientStreamer {
	return &clientStreamer{
		cmd:    cmd,
		stream: stream,
		ctx:    ctx,
		quitCh: make(chan struct{}),
		log:    log,
	}
}

func (s *clientStreamer) start() (workspaceapi.Pid, error) {
	req := &CommandMessage{
		Type: CommandMessage_TYPE_START,
		Start: &StartRequest{
			Path:      s.cmd.Path,
			Args:      s.cmd.Args,
			Dir:       s.cmd.Dir,
			Env:       s.cmd.Env,
			HasStdin:  s.cmd.Stdin != nil,
			HasStdout: s.cmd.Stdout != nil,
			HasStderr: s.cmd.Stderr != nil,
		},
	}

	if err := s.stream.Send(req); err != nil {
		return 0, fmt.Errorf("send start request: %w", err)
	}

	msg, err := s.stream.Recv()
	if err != nil {
		return 0, fmt.Errorf("recv started response: %w", err)
	}

	if msg.GetType() != CommandMessage_TYPE_STARTED || msg.GetStarted() == nil {
		return 0, fmt.Errorf("expected started response, got %v", msg.GetType())
	}

	pid := workspaceapi.Pid(msg.GetStarted().GetPid())

	// Start streaming I/O in background goroutines
	go s.streamIO()

	return pid, nil
}

func (s *clientStreamer) streamIO() {
	defer close(s.quitCh)

	// Stream stdin in background if available
	if s.cmd.Stdin != nil {
		go s.streamStdin()
	}

	// Receive stdout/stderr
	s.receiveOutput()
}

func (s *clientStreamer) streamStdin() {
	defer func() {
		_ = s.stream.CloseSend()
	}()

	buf := make([]byte, 64*1024)
	for {
		select {
		case <-s.quitCh:
			return
		case <-s.ctx.Done():
			return
		default:
		}

		n, err := s.cmd.Stdin.Read(buf)
		if err != nil && err != io.EOF {
			s.log.Error("read stdin", "error", err)
			return
		}

		if n > 0 {
			msg := &CommandMessage{
				Type: CommandMessage_TYPE_IO,
				Io: &IOData{
					Type: IOData_IO_STDIN,
					Data: buf[:n],
				},
			}
			if serr := s.stream.Send(msg); serr != nil {
				s.log.Error("send stdin", "error", serr)
				return
			}
		}

		if err == io.EOF {
			return
		}
	}
}

func (s *clientStreamer) receiveOutput() {
	var finalErr error

	for {
		msg, err := s.stream.Recv()
		if err != nil {
			if err != io.EOF {
				s.log.Error("recv message", "error", err)
				finalErr = err
			}
			break
		}

		switch msg.GetType() {
		case CommandMessage_TYPE_IO:
			io := msg.GetIo()
			if io == nil {
				continue
			}
			switch io.GetType() {
			case IOData_IO_STDOUT:
				if s.cmd.Stdout != nil {
					_, _ = s.cmd.Stdout.Write(io.GetData())
				}
			case IOData_IO_STDERR:
				if s.cmd.Stderr != nil {
					_, _ = s.cmd.Stderr.Write(io.GetData())
				}
			}

		case CommandMessage_TYPE_DONE:
			done := msg.GetDone()
			if done != nil && done.GetExitError() != "" {
				finalErr = fmt.Errorf("process exit: %s", done.GetExitError())
			}

		case CommandMessage_TYPE_ERROR:
			finalErr = fmt.Errorf("agent error: %s", msg.GetError())
		}
	}

	// Notify watcher if present
	if s.cmd.Watcher != nil && s.cmd.Watcher.WatchProcess() != nil {
		select {
		case s.cmd.Watcher.WatchProcess() <- finalErr:
		case <-time.After(2 * time.Minute):
			s.log.Warn("watcher not ready, dropping error")
		}
	}

	// Close stdout/stderr if they implement io.Closer
	if closer, ok := s.cmd.Stdout.(io.Closer); ok {
		_ = closer.Close()
	}
	if closer, ok := s.cmd.Stderr.(io.Closer); ok {
		_ = closer.Close()
	}
}

