/*
E2E Tests for Sandbox Security

These tests verify the security properties of the sandbox execution environment.
They require a real VM runtime and cannot run with mock implementations.

# Prerequisites

1. Platform Requirements:
   - Linux: KVM must be available (/dev/kvm)
   - macOS: Apple Silicon (arm64) required for Virtualization.framework

2. Container Images:
   The sandbox uses Matchlock to pull and build container images automatically.
   By default, it uses alpine:latest. Set SANDBOX_E2E_IMAGE to override:
     Example: export SANDBOX_E2E_IMAGE=python:3.12-alpine

# Running E2E Tests

	# Run all e2e tests (uses alpine:latest by default)
	go test -v -run TestE2E

	# Run with a specific image
	SANDBOX_E2E_IMAGE=ubuntu:22.04 go test -v -run TestE2E

	# Run specific security test
	go test -v -run TestE2E_ProcessIsolation

# Security Properties Verified

These tests verify the following security invariants:

1. Process Isolation: Host processes are not visible in the sandbox
2. Network Policy: Default-deny egress with allowlist support
3. Filesystem Isolation: Ephemeral root, read-only system paths
4. Environment Scrubbing: Sensitive environment variables are filtered
5. Resource Limits: Memory and disk quotas are enforced
6. Workspace Mount: Controlled bidirectional file sharing

# CI/CD Integration

For CI environments, ensure:
- KVM is available (use nested virtualization or bare metal)
- Network access for pulling container images (or pre-cached images)
- Sufficient resources for VM startup (recommended: 2+ CPU, 4GB+ RAM)
*/
package sandbox

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"runtime"
	"strings"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// e2eImage returns the container image to use for e2e tests.
// Set SANDBOX_E2E_IMAGE environment variable to override the default.
func e2eImage() string {
	if img := os.Getenv("SANDBOX_E2E_IMAGE"); img != "" {
		return img
	}
	return DefaultImage // alpine:latest
}

// skipE2E skips the test if e2e prerequisites are not met.
func skipE2E(t *testing.T) {
	t.Helper()

	// Check platform support
	switch runtime.GOOS {
	case "linux":
		if _, err := os.Stat("/dev/kvm"); os.IsNotExist(err) {
			t.Skip("KVM not available")
		}
	case "darwin":
		if runtime.GOARCH != "arm64" {
			t.Skip("Apple Silicon with native arm64 Go required (current GOARCH=" + runtime.GOARCH + ")")
		}
	default:
		t.Skipf("unsupported platform: %s", runtime.GOOS)
	}
}

// setupE2EExecutor creates a sandbox executor for e2e testing using the real runtime.
func setupE2EExecutor(t *testing.T, config Config) *Executor {
	t.Helper()
	skipE2E(t)

	if config.WorkspaceRoot == "" {
		config.WorkspaceRoot = t.TempDir()
	}

	if config.Image == "" {
		config.Image = e2eImage()
	}

	// Allow longer timeout for image pulling on first run
	ctx, cancel := context.WithTimeout(context.Background(), 120*time.Second)
	defer cancel()

	exec, err := New(ctx, config)
	require.NoError(t, err)
	t.Cleanup(func() { _ = exec.Close() })

	return exec
}

func runCommand(t *testing.T, exec *Executor, command string) (string, string) {
	t.Helper()

	stdout := &bytes.Buffer{}
	stderr := &bytes.Buffer{}
	watchCh := make(chan error, 1)

	cmd := workspaceapi.Cmd{
		Path:    "/bin/sh",
		Args:    []string{"-c", command},
		Stdout:  stdout,
		Stderr:  stderr,
		Watcher: &e2eWatcher{ch: watchCh},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	_, err := exec.Start(ctx, cmd)
	require.NoError(t, err)

	select {
	case <-watchCh:
	case <-ctx.Done():
		t.Fatalf("timeout waiting for command: %s", command)
	}

	return stdout.String(), stderr.String()
}

// e2eWatcher implements workspaceapi.ProcessWatcher for e2e tests.
type e2eWatcher struct {
	ch chan error
}

func (w *e2eWatcher) WatchProcess() chan error {
	return w.ch
}

func TestE2E_SimpleCommand(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	stdout, _ := runCommand(t, exec, "echo hello")
	assert.Equal(t, "hello\n", stdout)
}

func TestE2E_EnvironmentVariables(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	tsuite := []struct {
		name    string
		cmd     string
		wantOut string
	}{
		{
			name:    "echo with var",
			cmd:     "export FOO=bar && echo $FOO",
			wantOut: "bar\n",
		},
		{
			name:    "multiple vars",
			cmd:     "export A=1 B=2 && echo $A$B",
			wantOut: "12\n",
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			stdout, _ := runCommand(t, exec, tc.cmd)
			assert.Equal(t, tc.wantOut, stdout)
		})
	}
}

func TestE2E_WorkingDirectory(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Test default working directory
	stdout, _ := runCommand(t, exec, "pwd")
	assert.NotEmpty(t, stdout)

	// Test changing to specific directory
	stdout, _ = runCommand(t, exec, "cd /tmp && pwd")
	// On macOS /tmp is symlinked to /private/tmp, on Linux it's /tmp
	assert.Contains(t, stdout, "tmp")
}

func TestE2E_StderrCapture(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	stdout, stderr := runCommand(t, exec, "echo out; echo err >&2")
	assert.Equal(t, "out\n", stdout)
	assert.Equal(t, "err\n", stderr)
}

func TestE2E_ExitCode(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	watchCh := make(chan error, 1)
	cmd := workspaceapi.Cmd{
		Path:    "/bin/sh",
		Args:    []string{"-c", "exit 42"},
		Watcher: &e2eWatcher{ch: watchCh},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	_, err := exec.Start(ctx, cmd)
	require.NoError(t, err)

	select {
	case werr := <-watchCh:
		require.Error(t, werr)
		assert.Contains(t, werr.Error(), "42")
	case <-ctx.Done():
		t.Fatal("timeout")
	}
}

func TestE2E_ResourceLimits(t *testing.T) {
	tsuite := []struct {
		name      string
		resources ResourceConfig
		cmd       string
		wantErr   string
	}{
		{
			name:      "memory limit OOM",
			resources: ResourceConfig{CPUs: 1, MemoryMB: 64, DiskMB: 1024},
			cmd:       "head -c 128M /dev/zero | cat > /dev/null",
			wantErr:   "killed",
		},
		{
			name:      "disk quota exceeded",
			resources: ResourceConfig{CPUs: 1, MemoryMB: 256, DiskMB: 10},
			cmd:       "dd if=/dev/zero of=/tmp/big bs=1M count=20 2>&1",
			wantErr:   "No space left",
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			config := DefaultConfig()
			config.Resources = &tc.resources
			exec := setupE2EExecutor(t, config)
			_, stderr := runCommand(t, exec, tc.cmd)
			assert.Contains(t, stderr, tc.wantErr)
		})
	}
}

func TestE2E_NetworkPolicy(t *testing.T) {
	tsuite := []struct {
		name         string
		allowedHosts []string
		targetHost   string
		wantAllowed  bool
	}{
		{
			name:         "default deny",
			allowedHosts: nil,
			targetHost:   "example.com",
			wantAllowed:  false,
		},
		{
			name:         "allowed host",
			allowedHosts: []string{"api.github.com"},
			targetHost:   "api.github.com",
			wantAllowed:  true,
		},
		{
			name:         "blocked host",
			allowedHosts: []string{"api.github.com"},
			targetHost:   "google.com",
			wantAllowed:  false,
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			config := DefaultConfig()
			if tc.allowedHosts != nil {
				config.Policy.Network.AllowedHosts = tc.allowedHosts
			}
			exec := setupE2EExecutor(t, config)

			// Try to connect to the target host (use wget since alpine has it by default)
			cmd := "wget -q --spider --timeout=5 https://" + tc.targetHost + " 2>/dev/null && echo OK || echo BLOCKED"
			stdout, _ := runCommand(t, exec, cmd)

			if tc.wantAllowed {
				assert.Contains(t, stdout, "OK")
			} else {
				assert.Contains(t, stdout, "BLOCKED")
			}
		})
	}
}

func TestE2E_ProcessIsolation(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Get PIDs visible inside sandbox
	stdout, _ := runCommand(t, exec, "ps -eo pid --no-headers | wc -l")

	// In an isolated VM, we should see very few processes (init, sh, ps, wc)
	// Not thousands like on a typical host
	assert.NotEmpty(t, stdout)

	// Parse the process count and verify isolation
	var processCount int
	_, err := fmt.Sscanf(strings.TrimSpace(stdout), "%d", &processCount)
	require.NoError(t, err, "failed to parse process count")

	// A properly isolated VM should have fewer than 20 processes
	// Typical host has hundreds or thousands
	assert.Less(t, processCount, 20,
		"sandbox should have few visible processes, got %d", processCount)

	// Verify specific host processes are NOT visible
	// These are common host processes that should never appear in a sandbox
	stdout, _ = runCommand(t, exec, "ps aux")

	hostProcesses := []string{
		"systemd",      // Linux init system (unless sandbox uses it)
		"sshd",         // SSH daemon
		"dockerd",      // Docker daemon
		"containerd",   // Container runtime
		"launchd",      // macOS init system
		"WindowServer", // macOS display server
	}

	for _, proc := range hostProcesses {
		assert.NotContains(t, stdout, proc,
			"host process %q should not be visible in sandbox", proc)
	}

	// Verify PID 1 exists (init process in the sandbox)
	stdout, _ = runCommand(t, exec, "ps -p 1 -o comm= 2>/dev/null || echo 'no-pid-1'")
	assert.NotContains(t, stdout, "no-pid-1", "sandbox should have its own PID 1")
}

func TestE2E_EphemeralFilesystem(t *testing.T) {
	config := DefaultConfig()
	config.Policy.Filesystem.EphemeralRoot = true

	// First sandbox - create file
	exec1 := setupE2EExecutor(t, config)
	runCommand(t, exec1, "echo 'secret' > /tmp/testfile")
	_ = exec1.Close()

	// Second sandbox - file should not exist
	exec2 := setupE2EExecutor(t, config)
	_, stderr := runCommand(t, exec2, "cat /tmp/testfile")
	assert.Contains(t, stderr, "No such file")
}

func TestE2E_EnvironmentScrubbing(t *testing.T) {
	tsuite := []struct {
		name     string
		envVar   string
		envValue string
	}{
		{name: "github token", envVar: "GITHUB_TOKEN", envValue: "ghp_secret123"},
		{name: "aws secret", envVar: "AWS_SECRET_ACCESS_KEY", envValue: "wJalrXUtnFEMI"},
		{name: "api key", envVar: "API_KEY", envValue: "sk-proj-abc123"},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			t.Setenv(tc.envVar, tc.envValue)
			exec := setupE2EExecutor(t, DefaultConfig())
			stdout, _ := runCommand(t, exec, "env")
			assert.NotContains(t, stdout, tc.envValue)
		})
	}
}

func TestE2E_WorkspaceMount(t *testing.T) {
	config := DefaultConfig()
	config.WorkspaceRoot = t.TempDir()

	// Create a file in the workspace
	testFile := config.WorkspaceRoot + "/test.txt"
	err := os.WriteFile(testFile, []byte("hello from host"), 0644)
	require.NoError(t, err)

	exec := setupE2EExecutor(t, config)

	// Verify the file is visible in the sandbox
	stdout, _ := runCommand(t, exec, "cat /workspace/test.txt")
	assert.Equal(t, "hello from host", stdout)

	// Write a file from inside the sandbox
	runCommand(t, exec, "echo 'hello from sandbox' > /workspace/sandbox.txt")

	// Verify it's visible on the host
	content, err := os.ReadFile(config.WorkspaceRoot + "/sandbox.txt")
	require.NoError(t, err)
	assert.Equal(t, "hello from sandbox\n", string(content))
}

func TestE2E_ReadOnlyPaths(t *testing.T) {
	config := DefaultConfig()

	// Ensure default read-only paths are set
	require.NotNil(t, config.Policy)
	require.NotNil(t, config.Policy.Filesystem)
	require.NotEmpty(t, config.Policy.Filesystem.ReadOnlyPaths)

	exec := setupE2EExecutor(t, config)

	// Verify system paths are read-only
	tsuite := []struct {
		name string
		path string
		cmd  string
	}{
		{
			name: "/usr is read-only",
			path: "/usr",
			cmd:  "touch /usr/testfile 2>&1",
		},
		{
			name: "/bin is read-only",
			path: "/bin",
			cmd:  "touch /bin/testfile 2>&1",
		},
	}

	for _, tc := range tsuite {
		t.Run(tc.name, func(t *testing.T) {
			stdout, _ := runCommand(t, exec, tc.cmd)
			// Should fail with permission denied or read-only filesystem error
			assert.True(t,
				strings.Contains(stdout, "Read-only") ||
					strings.Contains(stdout, "Permission denied") ||
					strings.Contains(stdout, "Operation not permitted"),
				"write to %s should fail, got: %s", tc.path, stdout)
		})
	}
}

func TestE2E_HostFilesystemIsolation(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Verify sandbox cannot access host-specific paths
	hostPaths := []string{
		"/etc/passwd",        // Should exist but be sandbox's own
		"/etc/shadow",        // Should not be readable
		"/root",              // Should not have host's root home
		"/home",              // Should not have host's home directories
		"/Users",             // macOS home directories
		"/var/run/docker.sock", // Docker socket
	}

	for _, path := range hostPaths {
		t.Run(path, func(t *testing.T) {
			// Try to read the file
			stdout, stderr := runCommand(t, exec,
				fmt.Sprintf("cat %s 2>&1 || echo 'NOT_ACCESSIBLE'", path))

			combined := stdout + stderr

			// If the file exists, it should be the sandbox's version, not the host's
			// We verify by checking for common host-specific content
			if !strings.Contains(combined, "NOT_ACCESSIBLE") &&
				!strings.Contains(combined, "No such file") &&
				!strings.Contains(combined, "Permission denied") {
				// File is accessible - verify it's not the host's version
				if path == "/etc/passwd" {
					// Sandbox's passwd should not contain host usernames
					// (This is a heuristic check)
					assert.NotContains(t, stdout, os.Getenv("USER"),
						"sandbox /etc/passwd should not contain host username")
				}
			}
		})
	}
}

func TestE2E_NoHostNetworkNamespace(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Verify sandbox has its own network namespace
	// by checking that host network interfaces are not visible

	// Get network interfaces in sandbox
	stdout, _ := runCommand(t, exec, "ip link show 2>/dev/null || ifconfig -a 2>/dev/null || echo 'NO_NET_TOOLS'")

	if strings.Contains(stdout, "NO_NET_TOOLS") {
		t.Skip("network tools not available in sandbox image")
	}

	// Common host-only interfaces that should NOT appear in sandbox
	hostInterfaces := []string{
		"docker0",   // Docker bridge
		"br-",       // Docker custom bridges
		"veth",      // Docker veth pairs
		"virbr",     // libvirt bridges
		"vmnet",     // VMware interfaces
		"en0",       // macOS primary interface (should have different name in VM)
		"enp",       // Linux physical interfaces
		"wlp",       // Linux wireless interfaces
	}

	for _, iface := range hostInterfaces {
		// Note: Some of these might legitimately appear in a VM
		// This is a heuristic check
		if strings.Contains(stdout, iface) {
			t.Logf("Warning: interface %q visible in sandbox (may be false positive)", iface)
		}
	}

	// Verify sandbox has at least a loopback interface
	assert.True(t,
		strings.Contains(stdout, "lo") || strings.Contains(stdout, "loopback"),
		"sandbox should have loopback interface")
}

func TestE2E_TimeIsolation(t *testing.T) {
	exec := setupE2EExecutor(t, DefaultConfig())

	// Verify the sandbox has a reasonable time
	// (not checking exact match to avoid flakiness, just sanity check)
	stdout, _ := runCommand(t, exec, "date +%Y")

	var year int
	_, err := fmt.Sscanf(strings.TrimSpace(stdout), "%d", &year)
	require.NoError(t, err, "failed to parse year from sandbox")

	// Year should be reasonable (not 1970, not far future)
	assert.GreaterOrEqual(t, year, 2024, "sandbox year should be reasonable")
	assert.LessOrEqual(t, year, 2030, "sandbox year should be reasonable")
}

