//go:build darwin && arm64

package vzruntime

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/Code-Hex/vz/v3"
	"github.com/unstablebuild/rune-go-sdk/sandbox"
	"github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
)

const (
	agentConnectTimeout = 30 * time.Second
	agentPingInterval   = 100 * time.Millisecond
)

// VM represents a running sandbox virtual machine using Virtualization.framework.
type VM struct {
	id           string
	vm           *vz.VirtualMachine
	socketDevice *vz.VirtioSocketDevice
	config       *sandbox.Config
	tempRootfs   string
	state        sandbox.VMState
	log          *slog.Logger

	// gRPC connection to guest agent
	agentConn *grpc.ClientConn
	agent     sandboxrpc.AgentClient

	mu     sync.RWMutex
	closed bool
}

// newVM creates and starts a new VM with the given configuration.
func newVM(ctx context.Context, r *Runtime, config *sandbox.Config) (*VM, error) {
	vm := &VM{
		id:     generateID(),
		config: config,
		state:  sandbox.VMStateStarting,
		log:    slog.Default().With("component", "vzruntime.VM"),
	}

	// Copy rootfs to temp location for this VM instance
	tempRootfs, err := vm.copyRootfs(r.rootfsPath)
	if err != nil {
		return nil, fmt.Errorf("copy rootfs: %w", err)
	}
	vm.tempRootfs = tempRootfs

	// Configure the VM
	vzConfig, socketDevice, err := vm.createVMConfig(r.kernelPath, tempRootfs, config)
	if err != nil {
		os.Remove(tempRootfs)
		return nil, fmt.Errorf("create vm config: %w", err)
	}
	vm.socketDevice = socketDevice

	// Create the virtual machine
	vzVM, err := vz.NewVirtualMachine(vzConfig)
	if err != nil {
		os.Remove(tempRootfs)
		return nil, fmt.Errorf("create virtual machine: %w", err)
	}
	vm.vm = vzVM

	// Start the VM
	if err := vm.start(ctx); err != nil {
		os.Remove(tempRootfs)
		return nil, fmt.Errorf("start vm: %w", err)
	}

	// Connect to the guest agent
	if err := vm.connectAgent(ctx); err != nil {
		_ = vm.Close()
		return nil, fmt.Errorf("connect agent: %w", err)
	}

	vm.state = sandbox.VMStateRunning
	vm.log.Info("vm started", "id", vm.id)

	return vm, nil
}

// copyRootfs creates a copy of the rootfs for this VM instance.
func (v *VM) copyRootfs(srcPath string) (string, error) {
	tmpDir, err := os.MkdirTemp("", "rune-sandbox-*")
	if err != nil {
		return "", fmt.Errorf("create temp dir: %w", err)
	}

	dstPath := filepath.Join(tmpDir, "rootfs.ext4")

	src, err := os.Open(srcPath)
	if err != nil {
		os.RemoveAll(tmpDir)
		return "", fmt.Errorf("open source: %w", err)
	}
	defer src.Close()

	dst, err := os.Create(dstPath)
	if err != nil {
		os.RemoveAll(tmpDir)
		return "", fmt.Errorf("create dest: %w", err)
	}
	defer dst.Close()

	if _, err := io.Copy(dst, src); err != nil {
		os.RemoveAll(tmpDir)
		return "", fmt.Errorf("copy rootfs: %w", err)
	}

	return dstPath, nil
}

// createVMConfig creates the Virtualization.framework configuration.
func (v *VM) createVMConfig(
	kernelPath, rootfsPath string,
	config *sandbox.Config,
) (*vz.VirtualMachineConfiguration, *vz.VirtioSocketDevice, error) {
	// Boot loader
	cmdline := "console=hvc0 root=/dev/vda rw init=/init quiet"
	bootLoader, err := vz.NewLinuxBootLoader(kernelPath, vz.WithCommandLine(cmdline))
	if err != nil {
		return nil, nil, fmt.Errorf("create boot loader: %w", err)
	}

	// Resource configuration
	cpus := uint(1)
	memoryBytes := uint64(512 * 1024 * 1024) // 512 MB

	if config.Resources != nil {
		if config.Resources.CPUs > 0 {
			cpus = uint(config.Resources.CPUs)
		}
		if config.Resources.MemoryMB > 0 {
			memoryBytes = uint64(config.Resources.MemoryMB) * 1024 * 1024
		}
	}

	// Create VM configuration
	vmConfig, err := vz.NewVirtualMachineConfiguration(bootLoader, cpus, memoryBytes)
	if err != nil {
		return nil, nil, fmt.Errorf("create vm config: %w", err)
	}

	// Storage - rootfs as virtio block device
	diskAttachment, err := vz.NewDiskImageStorageDeviceAttachment(
		rootfsPath,
		false, // not read-only
	)
	if err != nil {
		return nil, nil, fmt.Errorf("create disk attachment: %w", err)
	}

	storageConfig, err := vz.NewVirtioBlockDeviceConfiguration(diskAttachment)
	if err != nil {
		return nil, nil, fmt.Errorf("create storage config: %w", err)
	}
	vmConfig.SetStorageDevicesVirtualMachineConfiguration([]*vz.VirtioBlockDeviceConfiguration{
		storageConfig,
	})

	// Network - NAT for internet access
	natAttachment, err := vz.NewNATNetworkDeviceAttachment()
	if err != nil {
		return nil, nil, fmt.Errorf("create nat attachment: %w", err)
	}

	netConfig, err := vz.NewVirtioNetworkDeviceConfiguration(natAttachment)
	if err != nil {
		return nil, nil, fmt.Errorf("create network config: %w", err)
	}
	vmConfig.SetNetworkDevicesVirtualMachineConfiguration([]*vz.VirtioNetworkDeviceConfiguration{
		netConfig,
	})

	// Serial console for debugging
	serialAttachment, err := vz.NewFileHandleSerialPortAttachment(os.Stdin, os.Stderr)
	if err != nil {
		return nil, nil, fmt.Errorf("create serial attachment: %w", err)
	}
	serialConfig, err := vz.NewVirtioConsoleDeviceSerialPortConfiguration(serialAttachment)
	if err != nil {
		return nil, nil, fmt.Errorf("create serial config: %w", err)
	}
	vmConfig.SetSerialPortsVirtualMachineConfiguration([]*vz.VirtioConsoleDeviceSerialPortConfiguration{
		serialConfig,
	})

	// Vsock - for host-guest communication
	socketConfig, err := vz.NewVirtioSocketDeviceConfiguration()
	if err != nil {
		return nil, nil, fmt.Errorf("create socket config: %w", err)
	}
	vmConfig.SetSocketDevicesVirtualMachineConfiguration([]vz.SocketDeviceConfiguration{
		socketConfig,
	})

	// Entropy device
	entropyConfig, err := vz.NewVirtioEntropyDeviceConfiguration()
	if err != nil {
		return nil, nil, fmt.Errorf("create entropy config: %w", err)
	}
	vmConfig.SetEntropyDevicesVirtualMachineConfiguration([]*vz.VirtioEntropyDeviceConfiguration{
		entropyConfig,
	})

	// Shared directory - workspace mounting via virtio-fs
	if config.WorkspaceRoot != "" {
		workspaceMountPoint := "/workspace"
		if config.Policy != nil && config.Policy.Filesystem != nil &&
			config.Policy.Filesystem.WorkspaceMountPoint != "" {
			workspaceMountPoint = config.Policy.Filesystem.WorkspaceMountPoint
		}

		readOnly := false
		if config.Policy != nil && config.Policy.Filesystem != nil {
			readOnly = config.Policy.Filesystem.ReadOnlyWorkspace
		}

		sharedDir, err := vz.NewSharedDirectory(config.WorkspaceRoot, readOnly)
		if err != nil {
			return nil, nil, fmt.Errorf("create shared directory: %w", err)
		}

		share, err := vz.NewSingleDirectoryShare(sharedDir)
		if err != nil {
			return nil, nil, fmt.Errorf("create directory share: %w", err)
		}

		// Use the mount point base name as the tag
		tag := filepath.Base(workspaceMountPoint)
		fsConfig, err := vz.NewVirtioFileSystemDeviceConfiguration(tag)
		if err != nil {
			return nil, nil, fmt.Errorf("create fs config: %w", err)
		}
		fsConfig.SetDirectoryShare(share)

		vmConfig.SetDirectorySharingDevicesVirtualMachineConfiguration(
			[]vz.DirectorySharingDeviceConfiguration{fsConfig},
		)
	}

	// Validate the configuration
	valid, err := vmConfig.Validate()
	if err != nil {
		return nil, nil, fmt.Errorf("validate config: %w", err)
	}
	if !valid {
		return nil, nil, errors.New("invalid vm configuration")
	}

	// Get the socket device for later vsock connection
	socketDevices := vmConfig.SocketDevices()
	if len(socketDevices) == 0 {
		return nil, nil, errors.New("no socket device configured")
	}

	socketDevice, ok := socketDevices[0].(*vz.VirtioSocketDevice)
	if !ok {
		return nil, nil, errors.New("socket device is not a VirtioSocketDevice")
	}

	return vmConfig, socketDevice, nil
}

// start starts the VM and waits for it to be running.
func (v *VM) start(ctx context.Context) error {
	// Start the VM
	if err := v.vm.Start(); err != nil {
		return fmt.Errorf("start vm: %w", err)
	}

	// Wait for VM to be running
	ticker := time.NewTicker(50 * time.Millisecond)
	defer ticker.Stop()

	timeout := time.After(30 * time.Second)
	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-timeout:
			return errors.New("timeout waiting for vm to start")
		case <-ticker.C:
			state := v.vm.State()
			if state == vz.VirtualMachineStateRunning {
				return nil
			}
			if state == vz.VirtualMachineStateError {
				return errors.New("vm entered error state")
			}
		}
	}
}

// connectAgent establishes a gRPC connection to the guest agent over vsock.
func (v *VM) connectAgent(ctx context.Context) error {
	timeoutCtx, cancel := context.WithTimeout(ctx, agentConnectTimeout)
	defer cancel()

	// Get the socket device from the running VM
	socketDevices := v.vm.SocketDevices()
	if len(socketDevices) == 0 {
		return errors.New("no socket device available")
	}
	v.socketDevice = socketDevices[0]

	// Wait for the guest agent to be ready and connect
	var conn net.Conn
	ticker := time.NewTicker(agentPingInterval)
	defer ticker.Stop()

	for {
		select {
		case <-timeoutCtx.Done():
			return fmt.Errorf("timeout connecting to agent: %w", timeoutCtx.Err())
		case <-ticker.C:
			c, err := v.socketDevice.Connect(uint32(vsockPort))
			if err != nil {
				v.log.Debug("agent not ready", "error", err)
				continue
			}
			conn = c
		}

		if conn != nil {
			break
		}
	}

	// Create gRPC connection over the vsock connection
	grpcConn, err := grpc.NewClient(
		"passthrough:///sandbox-agent",
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithContextDialer(func(_ context.Context, _ string) (net.Conn, error) {
			return conn, nil
		}),
	)
	if err != nil {
		conn.Close()
		return fmt.Errorf("create grpc connection: %w", err)
	}
	v.agentConn = grpcConn
	v.agent = sandboxrpc.NewAgentClient(grpcConn)

	// Ping the agent to verify it's ready
	pingCtx, pingCancel := context.WithTimeout(ctx, 5*time.Second)
	defer pingCancel()

	_, err = v.agent.Ping(pingCtx, &sandboxrpc.PingRequest{})
	if err != nil {
		grpcConn.Close()
		conn.Close()
		return fmt.Errorf("ping agent: %w", err)
	}

	v.log.Debug("connected to guest agent")
	return nil
}

// ID returns the VM identifier.
func (v *VM) ID() string {
	return v.id
}

// State returns the current VM state.
func (v *VM) State() sandbox.VMState {
	v.mu.RLock()
	defer v.mu.RUnlock()
	return v.state
}

// AgentConn returns a new connection to the guest agent.
func (v *VM) AgentConn() (net.Conn, error) {
	v.mu.RLock()
	defer v.mu.RUnlock()

	if v.closed {
		return nil, sandbox.ErrClosed
	}

	if v.socketDevice == nil {
		return nil, errors.New("socket device not available")
	}

	conn, err := v.socketDevice.Connect(uint32(vsockPort))
	if err != nil {
		return nil, fmt.Errorf("connect to agent: %w", err)
	}

	return conn, nil
}

// Exec executes a command in the VM and returns the result.
func (v *VM) Exec(
	ctx context.Context,
	command string,
	opts *sandbox.ExecOptions,
) (*sandbox.ExecResult, error) {
	v.mu.RLock()
	if v.closed {
		v.mu.RUnlock()
		return nil, sandbox.ErrClosed
	}
	v.mu.RUnlock()

	// Parse command into path and args
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return nil, sandbox.ErrInvalidCommand
	}
	path := parts[0]
	args := parts[1:]

	// Prepare environment
	var env []string
	if opts != nil && opts.Env != nil {
		for k, val := range opts.Env {
			env = append(env, k+"="+val)
		}
	}

	// Prepare working directory
	dir := "/workspace"
	if opts != nil && opts.WorkingDir != "" {
		dir = opts.WorkingDir
	}

	// Start command stream
	stream, err := v.agent.StartCommand(ctx)
	if err != nil {
		return nil, fmt.Errorf("start command stream: %w", err)
	}

	// Send start request
	startReq := &sandboxrpc.CommandMessage{
		Type: sandboxrpc.CommandMessage_TYPE_START,
		Start: &sandboxrpc.StartRequest{
			Path:      path,
			Args:      args,
			Dir:       dir,
			Env:       env,
			HasStdin:  opts != nil && opts.Stdin != nil,
			HasStdout: true,
			HasStderr: true,
		},
	}

	if err := stream.Send(startReq); err != nil {
		return nil, fmt.Errorf("send start request: %w", err)
	}

	// Receive started response
	msg, err := stream.Recv()
	if err != nil {
		return nil, fmt.Errorf("recv started response: %w", err)
	}
	if msg.GetType() != sandboxrpc.CommandMessage_TYPE_STARTED {
		return nil, fmt.Errorf("expected started response, got %v", msg.GetType())
	}

	// Stream stdin in background if provided
	if opts != nil && opts.Stdin != nil {
		go v.streamStdin(stream, opts.Stdin)
	}

	// Collect output
	var stdout, stderr bytes.Buffer
	var exitCode int

	for {
		msg, err := stream.Recv()
		if err != nil {
			if err == io.EOF {
				break
			}
			return nil, fmt.Errorf("recv message: %w", err)
		}

		switch msg.GetType() {
		case sandboxrpc.CommandMessage_TYPE_IO:
			ioData := msg.GetIo()
			if ioData == nil {
				continue
			}
			switch ioData.GetType() {
			case sandboxrpc.IOData_IO_STDOUT:
				if opts != nil && opts.Stdout != nil {
					opts.Stdout.Write(ioData.GetData())
				}
				stdout.Write(ioData.GetData())
			case sandboxrpc.IOData_IO_STDERR:
				if opts != nil && opts.Stderr != nil {
					opts.Stderr.Write(ioData.GetData())
				}
				stderr.Write(ioData.GetData())
			}

		case sandboxrpc.CommandMessage_TYPE_DONE:
			done := msg.GetDone()
			if done != nil {
				exitCode = int(done.GetExitCode())
			}

		case sandboxrpc.CommandMessage_TYPE_ERROR:
			return nil, fmt.Errorf("agent error: %s", msg.GetError())
		}
	}

	return &sandbox.ExecResult{
		ExitCode: exitCode,
		Stdout:   stdout.Bytes(),
		Stderr:   stderr.Bytes(),
	}, nil
}

func (v *VM) streamStdin(stream sandboxrpc.Agent_StartCommandClient, stdin io.Reader) {
	defer stream.CloseSend()

	buf := make([]byte, 64*1024)
	for {
		n, err := stdin.Read(buf)
		if err != nil {
			return
		}
		if n > 0 {
			msg := &sandboxrpc.CommandMessage{
				Type: sandboxrpc.CommandMessage_TYPE_IO,
				Io: &sandboxrpc.IOData{
					Type: sandboxrpc.IOData_IO_STDIN,
					Data: buf[:n],
				},
			}
			if err := stream.Send(msg); err != nil {
				return
			}
		}
	}
}

// WriteFile writes content to a file in the VM.
func (v *VM) WriteFile(
	ctx context.Context,
	path string,
	content []byte,
	mode uint32,
) error {
	// Use cat to write the file via exec
	// This is simpler than extending the protocol
	cmd := fmt.Sprintf("cat > %s && chmod %o %s", path, mode, path)
	_, err := v.Exec(ctx, cmd, &sandbox.ExecOptions{
		Stdin: bytes.NewReader(content),
	})
	return err
}

// ReadFile reads a file from the VM.
func (v *VM) ReadFile(ctx context.Context, path string) ([]byte, error) {
	result, err := v.Exec(ctx, "cat "+path, nil)
	if err != nil {
		return nil, err
	}
	if result.ExitCode != 0 {
		return nil, fmt.Errorf("read file failed: %s", string(result.Stderr))
	}
	return result.Stdout, nil
}

// Close stops and destroys the VM.
func (v *VM) Close() error {
	v.mu.Lock()
	defer v.mu.Unlock()

	if v.closed {
		return nil
	}
	v.closed = true
	v.state = sandbox.VMStateStopping

	var errs []error

	// Close gRPC connection
	if v.agentConn != nil {
		if err := v.agentConn.Close(); err != nil {
			errs = append(errs, fmt.Errorf("close agent conn: %w", err))
		}
	}

	// Stop the VM
	if v.vm != nil {
		if v.vm.CanStop() {
			if err := v.vm.Stop(); err != nil {
				errs = append(errs, fmt.Errorf("stop vm: %w", err))
			}
		}
	}

	// Cleanup temp rootfs
	if v.tempRootfs != "" {
		dir := filepath.Dir(v.tempRootfs)
		if err := os.RemoveAll(dir); err != nil {
			errs = append(errs, fmt.Errorf("cleanup rootfs: %w", err))
		}
	}

	v.state = sandbox.VMStateStopped
	v.log.Info("vm stopped", "id", v.id)

	return errors.Join(errs...)
}

// generateID generates a unique VM ID.
func generateID() string {
	return fmt.Sprintf("vz-%d", time.Now().UnixNano())
}

// Ensure VM implements ExecutableVM.
var _ sandbox.ExecutableVM = (*VM)(nil)

