package vzruntime

import (
	"bytes"
	"compress/gzip"
	"fmt"
	"io"
	"os"

	"github.com/klauspost/compress/zstd"
	"github.com/unstablebuild/rune-go-sdk/sandbox/vzruntime/images"
)

// extractKernel extracts the embedded kernel to the destination path.
func extractKernel(destPath string) error {
	data := images.KernelArm64
	if len(data) == 0 {
		return fmt.Errorf("no embedded kernel (run scripts/build-guest-images.sh)")
	}

	return decompressGzip(data, destPath)
}

// extractRootfs extracts the embedded rootfs to the destination path.
func extractRootfs(destPath string) error {
	data := images.RootfsArm64
	if len(data) == 0 {
		return fmt.Errorf("no embedded rootfs (run scripts/build-guest-images.sh)")
	}

	return decompressZstd(data, destPath)
}

// decompressGzip decompresses gzip data to the destination file.
func decompressGzip(data []byte, destPath string) error {
	reader, err := gzip.NewReader(bytes.NewReader(data))
	if err != nil {
		return fmt.Errorf("create gzip reader: %w", err)
	}
	defer reader.Close()

	return writeFile(reader, destPath)
}

// decompressZstd decompresses zstd data to the destination file.
func decompressZstd(data []byte, destPath string) error {
	decoder, err := zstd.NewReader(bytes.NewReader(data))
	if err != nil {
		return fmt.Errorf("create zstd decoder: %w", err)
	}
	defer decoder.Close()

	return writeFile(decoder, destPath)
}

// writeFile writes data from a reader to a file atomically.
func writeFile(r io.Reader, destPath string) error {
	// Write to temp file first
	tmpPath := destPath + ".tmp"
	f, err := os.Create(tmpPath)
	if err != nil {
		return fmt.Errorf("create temp file: %w", err)
	}

	_, err = io.Copy(f, r)
	if closeErr := f.Close(); err == nil && closeErr != nil {
		err = closeErr
	}
	if err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("write file: %w", err)
	}

	// Atomic rename
	if err := os.Rename(tmpPath, destPath); err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("rename: %w", err)
	}

	return nil
}

