// guest-agent is the guest agent that runs inside the sandbox VM.
// It listens on vsock port 5000 for gRPC connections from the host
// and executes commands on behalf of the host.
//
// Build: GOOS=linux GOARCH=arm64 CGO_ENABLED=0 go build -ldflags="-s -w" -o guest-agent
package main

import (
	"log"
	"log/slog"
	"net"
	"os"
	"strconv"

	"github.com/mdlayher/vsock"
	"github.com/unstablebuild/rune-go-sdk/sandbox/sandboxrpc"
	"google.golang.org/grpc"
)

const (
	// vsockPort is the port the guest agent listens on.
	vsockPort = 5000
)

func main() {
	// Configure logging
	handler := slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{
		Level: slog.LevelDebug,
	})
	slog.SetDefault(slog.New(handler))

	log.Printf("guest-agent starting on vsock port %d", vsockPort)

	// Listen on vsock
	listener, err := listenVsock(vsockPort)
	if err != nil {
		log.Fatalf("failed to listen on vsock: %v", err)
	}
	defer listener.Close()

	log.Printf("guest-agent listening on vsock port %d", vsockPort)

	// Create gRPC server
	server := grpc.NewServer()

	// Register the agent service
	agent := sandboxrpc.NewServer()
	sandboxrpc.RegisterAgentServer(server, agent)

	// Serve
	if err := server.Serve(listener); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}

// listenVsock creates a vsock listener on the given port.
// It tries the modern vsock package first, then falls back to a file-based approach.
func listenVsock(port uint32) (net.Listener, error) {
	// Try using the vsock package (Linux 4.8+)
	listener, err := vsock.Listen(port, nil)
	if err == nil {
		return listener, nil
	}

	// Fallback: try opening /dev/vsock directly
	// This might be needed on some systems
	log.Printf("vsock.Listen failed (%v), trying fallback", err)
	return listenVsockFallback(port)
}

// listenVsockFallback provides a fallback vsock listener.
func listenVsockFallback(port uint32) (net.Listener, error) {
	// Create a simple TCP listener on localhost as ultimate fallback
	// This should rarely be needed as vsock.Listen should work in the VM
	return net.Listen("tcp", "127.0.0.1:"+strconv.Itoa(int(port)))
}

