	VSockPort = 5000
)

// Config contains configuration for creating a VM.
// This mirrors sandbox.Config to avoid import cycles.
type Config struct {
	// WorkspaceRoot is the path to the workspace directory to mount in the VM.
	WorkspaceRoot string

	// WorkspaceMountPoint is where to mount the workspace in the guest.
	// Defaults to "/workspace".
	WorkspaceMountPoint string

	// ReadOnlyWorkspace makes the workspace mount read-only.
	ReadOnlyWorkspace bool

	// CPUs is the number of virtual CPUs.
	CPUs int

	// MemoryMB is the amount of memory in megabytes.
	MemoryMB int
}

// ExecOptions contains options for command execution.
type ExecOptions struct {
	WorkingDir string
	Env        map[string]string
	Stdin      io.Reader
	Stdout     io.Writer
	Stderr     io.Writer
}

// ExecResult contains the result of command execution.
type ExecResult struct {
	ExitCode int
	Stdout   []byte
	Stderr   []byte
}

// Runtime implements a sandbox runtime using Virtualization.framework directly.
type Runtime struct {
	cacheDir   string
	kernelPath string
	rootfsPath string

	mu        sync.Mutex
	extracted bool
}

// NewRuntime creates a new vzRuntime instance.
// Images are extracted lazily on first VM creation.
func NewRuntime() (*Runtime, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return nil, fmt.Errorf("get home dir: %w", err)
	}

	cacheDir := filepath.Join(home, ".cache", "rune-sandbox", cacheVersion)

	return &Runtime{
		cacheDir:   cacheDir,
		kernelPath: filepath.Join(cacheDir, "vmlinuz-arm64"),
		rootfsPath: filepath.Join(cacheDir, "rootfs-arm64.ext4"),
	}, nil
}

// Create creates a new VM with the given configuration.
func (r *Runtime) Create(ctx context.Context, config *Config) (*VM, error) {
	if config == nil {
		config = &Config{}
	}

	// Apply defaults
	if config.CPUs <= 0 {
		config.CPUs = 1
	}
	if config.MemoryMB <= 0 {
		config.MemoryMB = 512
	}
	if config.WorkspaceMountPoint == "" {
		config.WorkspaceMountPoint = "/workspace"
	}

	// Extract embedded images if not already done
	if err := r.ensureImages(); err != nil {
		return nil, fmt.Errorf("extract images: %w", err)
	}

	// Create and start the VM
	vm, err := newVM(ctx, r, config)
	if err != nil {
		return nil, err
	}

	return vm, nil
}

// ensureImages extracts embedded kernel and rootfs to the cache directory.
func (r *Runtime) ensureImages() error {
	r.mu.Lock()
	defer r.mu.Unlock()

	if r.extracted {
		return nil
	}

	// Check if already extracted
	if r.imagesExist() {
		r.extracted = true
		return nil
	}

	// Create cache directory
	if err := os.MkdirAll(r.cacheDir, 0755); err != nil {
		return fmt.Errorf("create cache dir: %w", err)
	}

	// Extract kernel
	if err := extractKernel(r.kernelPath); err != nil {
		return fmt.Errorf("extract kernel: %w", err)
	}

	// Extract rootfs
	if err := extractRootfs(r.rootfsPath); err != nil {
		return fmt.Errorf("extract rootfs: %w", err)
	}

	r.extracted = true
	return nil
}

// imagesExist checks if the cached images exist and are valid.
func (r *Runtime) imagesExist() bool {
	kernelInfo, err := os.Stat(r.kernelPath)
	if err != nil || kernelInfo.Size() == 0 {
		return false
	}

	rootfsInfo, err := os.Stat(r.rootfsPath)
	if err != nil || rootfsInfo.Size() == 0 {
		return false
	}

	return true
}

