   351→	// Create gRPC connection over the vsock connection
   352→	grpcConn, err := grpc.NewClient(
   353→		"passthrough:///sandbox-agent",
   354→		grpc.WithTransportCredentials(insecure.NewCredentials()),
   355→		grpc.WithContextDialer(func(_ context.Context, _ string) (net.Conn, error) {
   356→			return conn, nil
   357→		}),
   358→	)
   359→	if err != nil {
   360→		conn.Close()
   361→		return fmt.Errorf("create grpc connection: %w", err)
   362→	}
   363→	v.agentConn = grpcConn
   364→	v.agent = sandboxrpc.NewAgentClient(grpcConn)
   365→
   366→	// Ping the agent to verify it's ready
   367→	pingCtx, pingCancel := context.WithTimeout(ctx, 5*time.Second)
   368→	defer pingCancel()
   369→
   370→	_, err = v.agent.Ping(pingCtx, &sandboxrpc.PingRequest{})
   371→	if err != nil {
   372→		grpcConn.Close()
   373→		conn.Close()
   374→		return fmt.Errorf("ping agent: %w", err)
   375→	}
   376→
   377→	v.log.Debug("connected to guest agent")
   378→	return nil
   379→}
