   414→// Exec executes a command in the VM and returns the result.
   415→func (v *VM) Exec(
   416→	ctx context.Context,
   417→	command string,
   418→	opts *ExecOptions,
   419→) (*ExecResult, error) {
   420→	v.mu.RLock()
   421→	if v.closed {
   422→		v.mu.RUnlock()
   423→		return nil, errors.New("vm closed")
   424→	}
   425→	v.mu.RUnlock()
   426→
   427→	// Parse command into path and args
   428→	parts := strings.Fields(command)
   429→	if len(parts) == 0 {
   430→		return nil, errors.New("empty command")
   431→	}
   432→	path := parts[0]
   433→	args := parts[1:]
   434→
   435→	// Prepare environment
   436→	var env []string
   437→	if opts != nil && opts.Env != nil {
   438→		for k, val := range opts.Env {
   439→			env = append(env, k+"="+val)
   440→		}
   441→	}
   442→
   443→	// Prepare working directory
   444→	dir := "/workspace"
   445→	if opts != nil && opts.WorkingDir != "" {
   446→		dir = opts.WorkingDir
   447→	}
   448→
   449→	// Start command stream
   450→	stream, err := v.agent.StartCommand(ctx)
   451→	if err != nil {
   452→		return nil, fmt.Errorf("start command stream: %w", err)
   453→	}
   454→
   455→	// Send start request
   456→	startReq := &sandboxrpc.CommandMessage{
   457→		Type: sandboxrpc.CommandMessage_TYPE_START,
   458→		Start: &sandboxrpc.StartRequest{
   459→			Path:      path,
   460→			Args:      args,
   461→			Dir:       dir,
   462→			Env:       env,
   463→			HasStdin:  opts != nil && opts.Stdin != nil,
   464→			HasStdout: true,
   465→			HasStderr: true,
   466→		},
   467→	}
   468→
   469→	if err := stream.Send(startReq); err != nil {
   470→		return nil, fmt.Errorf("send start request: %w", err)
   471→	}
   472→
   473→	// Receive started response
   474→	msg, err := stream.Recv()
   475→	if err != nil {
   476→		return nil, fmt.Errorf("recv started response: %w", err)
   477→	}
   478→	if msg.GetType() != sandboxrpc.CommandMessage_TYPE_STARTED {
   479→		return nil, fmt.Errorf("expected started response, got %v", msg.GetType())
   480→	}
   481→
   482→	// Stream stdin in background if provided
   483→	if opts != nil && opts.Stdin != nil {
   484→		go v.streamStdin(stream, opts.Stdin)
   485→	}
   486→
   487→	// Collect output
   488→	var stdout, stderr bytes.Buffer
   489→	var exitCode int
   490→
   491→	for {
   492→		msg, err := stream.Recv()
   493→		if err != nil {
   494→			if err == io.EOF {
   495→				break
   496→			}
   497→			return nil, fmt.Errorf("recv message: %w", err)
   498→		}
   499→
   500→		switch msg.GetType() {
   501→		case sandboxrpc.CommandMessage_TYPE_IO:
   502→			ioData := msg.GetIo()
   503→			if ioData == nil {
   504→				continue
   505→			}
   506→			switch ioData.GetType() {
   507→			case sandboxrpc.IOData_IO_STDOUT:
   508→				if opts != nil && opts.Stdout != nil {
   509→					opts.Stdout.Write(ioData.GetData())
   510→				}
   511→				stdout.Write(ioData.GetData())
   512→			case sandboxrpc.IOData_IO_STDERR:
   513→				if opts != nil && opts.Stderr != nil {
   514→					opts.Stderr.Write(ioData.GetData())
   515→				}
   516→				stderr.Write(ioData.GetData())
   517→			}
   518→
   519→		case sandboxrpc.CommandMessage_TYPE_DONE:
   520→			done := msg.GetDone()
   521→			if done != nil {
   522→				exitCode = int(done.GetExitCode())
   523→			}
   524→
   525→		case sandboxrpc.CommandMessage_TYPE_ERROR:
   526→			return nil, fmt.Errorf("agent error: %s", msg.GetError())
   527→		}
   528→	}
   529→
   530→	return &ExecResult{
   531→		ExitCode: exitCode,
   532→		Stdout:   stdout.Bytes(),
   533→		Stderr:   stderr.Bytes(),
   534→	}, nil
   535→}
   536→
   537→func (v *VM) streamStdin(stream sandboxrpc.Agent_StartCommandClient, stdin io.Reader) {
   538→	defer stream.CloseSend()
   539→
   540→	buf := make([]byte, 64*1024)
   541→	for {
   542→		n, err := stdin.Read(buf)
   543→		if err != nil {
   544→			return
   545→		}
   546→		if n > 0 {
   547→			msg := &sandboxrpc.CommandMessage{
   548→				Type: sandboxrpc.CommandMessage_TYPE_IO,
   549→				Io: &sandboxrpc.IOData{
   550→					Type: sandboxrpc.IOData_IO_STDIN,
   551→					Data: buf[:n],
   552→				},
   553→			}
   554→			if err := stream.Send(msg); err != nil {
   555→				return
   556→			}
   557→		}
   558→	}
   559→}
   560→
   561→// WriteFile writes content to a file in the VM.
   562→func (v *VM) WriteFile(
   563→	ctx context.Context,
   564→	path string,
   565→	content []byte,
   566→	mode uint32,
   567→) error {
   568→	// Use cat to write the file via exec
   569→	// This is simpler than extending the protocol
   570→	cmd := fmt.Sprintf("cat > %s && chmod %o %s", path, mode, path)
   571→	_, err := v.Exec(ctx, cmd, &ExecOptions{
   572→		Stdin: bytes.NewReader(content),
   573→	})
   574→	return err
   575→}
   576→
   577→// ReadFile reads a file from the VM.
   578→func (v *VM) ReadFile(ctx context.Context, path string) ([]byte, error) {
   579→	result, err := v.Exec(ctx, "cat "+path, nil)
   580→	if err != nil {
   581→		return nil, err
   582→	}
   583→	if result.ExitCode != 0 {
   584→		return nil, fmt.Errorf("read file failed: %s", string(result.Stderr))
   585→	}
   586→	return result.Stdout, nil
   587→}
   588→
   589→// Close stops and destroys the VM.
   590→func (v *VM) Close() error {
   591→	v.mu.Lock()
   592→	defer v.mu.Unlock()
   593→
   594→	if v.closed {
   595→		return nil
   596→	}
   597→	v.closed = true
   598→	v.state = VMStateStopping
   599→
   600→	var errs []error
   601→
   602→	// Close gRPC connection
   603→	if v.agentConn != nil {
   604→		if err := v.agentConn.Close(); err != nil {
   605→			errs = append(errs, fmt.Errorf("close agent conn: %w", err))
   606→		}
   607→	}
   608→
   609→	// Stop the VM
   610→	if v.vm != nil {
   611→		if v.vm.CanStop() {
   612→			if err := v.vm.Stop(); err != nil {
   613→				errs = append(errs, fmt.Errorf("stop vm: %w", err))
   614→			}
   615→		}
   616→	}
   617→
   618→	// Cleanup temp rootfs
   619→	if v.tempRootfs != "" {
   620→		dir := filepath.Dir(v.tempRootfs)
   621→		if err := os.RemoveAll(dir); err != nil {
   622→			errs = append(errs, fmt.Errorf("cleanup rootfs: %w", err))
   623→		}
   624→	}
   625→
   626→	v.state = VMStateStopped
   627→	v.log.Info("vm stopped", "id", v.id)
   628→
   629→	return errors.Join(errs...)
   630→}
   631→
   632→// generateID generates a unique VM ID.
   633→func generateID() string {
   634→	return fmt.Sprintf("vz-%d", time.Now().UnixNano())
   635→}
