package policy

// FilesystemPolicy defines filesystem access constraints for a sandbox.
type FilesystemPolicy struct {
	// EphemeralRoot when true means the root filesystem is ephemeral
	// and changes are discarded after the sandbox is destroyed.
	EphemeralRoot bool

	// ReadOnlyPaths is a list of paths that should be mounted read-only.
	ReadOnlyPaths []string

	// HiddenPaths is a list of paths that should be hidden from the sandbox.
	HiddenPaths []string

	// WorkspaceMountPoint is where the workspace directory is mounted
	// inside the sandbox. Default: /workspace
	WorkspaceMountPoint string
}

// DefaultFilesystemPolicy returns a FilesystemPolicy with secure defaults.
func DefaultFilesystemPolicy() *FilesystemPolicy {
	return &FilesystemPolicy{
		EphemeralRoot:       true,
		ReadOnlyPaths:       []string{"/usr", "/bin", "/lib", "/lib64"},
		HiddenPaths:         nil,
		WorkspaceMountPoint: "/workspace",
	}
}

// AddReadOnlyPath adds a path to the read-only list.
func (p *FilesystemPolicy) AddReadOnlyPath(path string) {
	p.ReadOnlyPaths = append(p.ReadOnlyPaths, path)
}

// AddHiddenPath adds a path to the hidden list.
func (p *FilesystemPolicy) AddHiddenPath(path string) {
	p.HiddenPaths = append(p.HiddenPaths, path)
}

