package sandbox

import (
	"fmt"
	"os/exec"
	"strings"
)

// DependencyError indicates a missing system dependency.
type DependencyError struct {
	Missing      []string
	Instructions string
}

func (e *DependencyError) Error() string {
	return fmt.Sprintf("missing dependencies: %s\n\n%s",
		strings.Join(e.Missing, ", "), e.Instructions)
}

// CheckDependencies verifies that all required system dependencies are available.
// Returns nil if all dependencies are satisfied, or a DependencyError with
// installation instructions.
func CheckDependencies() error {
	var missing []string

	// e2fsprogs tools - required for ext4 image manipulation
	e2fsTools := []string{"mke2fs", "debugfs", "resize2fs"}
	for _, tool := range e2fsTools {
		if _, err := exec.LookPath(tool); err != nil {
			// On Linux, mkfs.ext4 is an alias for mke2fs
			if tool == "mke2fs" {
				if _, err := exec.LookPath("mkfs.ext4"); err == nil {
					continue
				}
			}
			missing = append(missing, tool)
		}
	}

	if len(missing) == 0 {
		return nil
	}

	instructions := `Install e2fsprogs using your package manager:

    # Debian/Ubuntu
    sudo apt-get install e2fsprogs

    # Fedora/RHEL/CentOS
    sudo dnf install e2fsprogs

    # Arch Linux
    sudo pacman -S e2fsprogs`

	return &DependencyError{
		Missing:      missing,
		Instructions: instructions,
	}
}

// checkE2fsprogs is a quick check for e2fsprogs availability.
// Returns an error with installation instructions if not found.
func checkE2fsprogs() error {
	// Check for mke2fs (or mkfs.ext4 on Linux)
	if _, err := exec.LookPath("mke2fs"); err != nil {
		if _, err := exec.LookPath("mkfs.ext4"); err == nil {
			return nil
		}
		return CheckDependencies()
	}
	return nil
}

